import{_ as a}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as t,o,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const s=JSON.parse('{"title":"Cloudflare API Token 설정","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Safety/cloudflare-api-token.md","filePath":"ko-KR/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),r={name:"ko-KR/Safety/cloudflare-api-token.md"};function i(n,e,h,k,p,c){return o(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="cloudflare-api-token-설정" tabindex="-1">Cloudflare API Token 설정 <a class="header-anchor" href="#cloudflare-api-token-설정" aria-label="Permalink to &quot;Cloudflare API Token 설정&quot;">​</a></h1><p>ImgBed의 일부 기능은 Cloudflare API Token을 사용합니다. 예를 들어 R2, Workers, D1, KV 같은 Cloudflare 리소스를 조작할 때 필요합니다.</p><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>Cloudflare 계정</td><td>API Token 생성</td></tr><tr><td>대상 Account ID</td><td>R2, Workers 등 작업 대상 식별</td></tr><tr><td>필요한 권한</td><td>기능에 맞는 최소 권한 부여</td></tr></tbody></table><h2 id="api-token-만들기" tabindex="-1">API Token 만들기 <a class="header-anchor" href="#api-token-만들기" aria-label="Permalink to &quot;API Token 만들기&quot;">​</a></h2><ol><li>Cloudflare Dashboard에 로그인합니다.</li><li>오른쪽 위 프로필에서 <code>My Profile</code>을 엽니다.</li><li><code>API Tokens</code>로 이동합니다.</li><li><code>Create Token</code>을 누릅니다.</li><li>필요한 권한을 선택합니다.</li><li>대상 계정 또는 Zone을 지정합니다.</li><li>생성 후 표시되는 Token을 복사합니다.</li></ol><p>![Cloudflare API Token](../../image/Safety/cloudflare api token截图.png)</p><p>Token은 생성 직후에만 보이는 경우가 많습니다. 반드시 안전한 곳에 보관하세요.</p><h2 id="global-api-key와의-차이" tabindex="-1">Global API Key와의 차이 <a class="header-anchor" href="#global-api-key와의-차이" aria-label="Permalink to &quot;Global API Key와의 차이&quot;">​</a></h2><p>Cloudflare에는 Global API Key도 있지만, 일반적으로는 API Token을 권장합니다.</p><table tabindex="0"><thead><tr><th>종류</th><th>특징</th></tr></thead><tbody><tr><td>API Token</td><td>권한과 대상 범위를 제한할 수 있음</td></tr><tr><td>Global API Key</td><td>계정 전체에 강한 권한을 가짐</td></tr></tbody></table><p>필요한 권한만 가진 API Token을 쓰는 편이 운영상 더 안전합니다.</p><p><img src="'+a+'" alt="Global API Key 확인" loading="lazy"></p><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><p>ImgBed 설정 화면에서 Cloudflare API Token을 입력하고 저장합니다.</p><p>저장 후 관련 기능에서 연결 확인이나 용량 확인을 실행해 Token이 정상 작동하는지 확인합니다.</p><h2 id="운영-주의사항" tabindex="-1">운영 주의사항 <a class="header-anchor" href="#운영-주의사항" aria-label="Permalink to &quot;운영 주의사항&quot;">​</a></h2><ul><li>Token을 공개 저장소나 프론트엔드 코드에 직접 넣지 마세요.</li><li>권한은 필요한 범위로만 제한합니다.</li><li>더 이상 쓰지 않는 Token은 Cloudflare에서 삭제합니다.</li><li>유출 가능성이 있으면 즉시 폐기하고 새로 발급하세요.</li></ul>',18)])])}const b=t(r,[["render",i]]);export{s as __pageData,b as default};
